mapper.select:
SELECT id, profit_no, order_no, merchant_no, merchant_name, agent_merchant_no, agent_merchant_name, agent_level, order_amount, fee_amount, profit_amount, commission_rate, settle_date, profit_status, settlement_id, settlement_no, remark, created_at, updated_at, deleted FROM agent_profit_record
deleted = 0
AND profit_no = #{params.profitNo}
AND order_no = #{params.orderNo}
AND merchant_no = #{params.merchantNo}
AND agent_merchant_no = #{params.agentMerchantNo}
AND agent_level = #{params.agentLevel}
AND profit_status = #{params.profitStatus}
AND settle_date = #{params.settleDate}
AND created_at >= #{params.startDate}
AND created_at <= #{params.endDate}
ORDER BY created_at DESC

SELECT COALESCE(SUM(profit_amount), 0)
FROM agent_profit_record
WHERE deleted = 0
  AND agent_merchant_no = #{agentMerchantNo}

      AND profit_status = #{profitStatus}
